Here's a solid pattern for testing `DataFetcher` with MSTest, covering mocking, timeouts, and cancellation:

```csharp
[TestClass]
public class DataFetcherTests
{
    // Reusable mock handler for HttpClient
    private static HttpClient CreateMockClient(
        HttpStatusCode statusCode,
        string content = "",
        TimeSpan? delay = null)
    {
        var handler = new MockHttpMessageHandler(async (req, ct) =>
        {
            if (delay.HasValue)
                await Task.Delay(delay.Value, ct);

            return new HttpResponseMessage(statusCode)
            {
                Content = new StringContent(content)
            };
        });
        return new HttpClient(handler);
    }

    // ── Success path ──

    [TestMethod]
    public async Task FetchAsync_ReturnsContent_OnSuccess()
    {
        using var client = CreateMockClient(HttpStatusCode.OK, "hello");
        var fetcher = new DataFetcher(client);

        var result = await fetcher.FetchAsync("https://example.com");

        Assert.AreEqual("hello", result);
    }

    // ── HTTP error ──

    [TestMethod]
    public async Task FetchAsync_Throws_OnHttpError()
    {
        using var client = CreateMockClient(HttpStatusCode.InternalServerError);
        var fetcher = new DataFetcher(client);

        await Assert.ThrowsExceptionAsync<HttpRequestException>(
            () => fetcher.FetchAsync("https://example.com"));
    }

    // ── Caller-driven cancellation ──

    [TestMethod]
    public async Task FetchAsync_Throws_WhenCallerCancels()
    {
        // Handler delays long enough for us to cancel first
        using var client = CreateMockClient(HttpStatusCode.OK, "data", delay: TimeSpan.FromSeconds(30));
        var fetcher = new DataFetcher(client);

        using var cts = new CancellationTokenSource();
        cts.Cancel(); // cancel immediately

        await Assert.ThrowsExceptionAsync<TaskCanceledException>(
            () => fetcher.FetchAsync("https://example.com", cts.Token));
    }

    // ── Timeout via CancellationTokenSource ──

    [TestMethod]
    public async Task FetchAsync_Throws_WhenTimeoutExpires()
    {
        using var client = CreateMockClient(HttpStatusCode.OK, "data", delay: TimeSpan.FromSeconds(30));
        var fetcher = new DataFetcher(client);

        using var cts = new CancellationTokenSource(TimeSpan.FromMilliseconds(50));

        await Assert.ThrowsExceptionAsync<TaskCanceledException>(
            () => fetcher.FetchAsync("https://example.com", cts.Token));
    }

    // ── MSTest [Timeout] as safety net ──

    [TestMethod]
    [Timeout(5000)] // fails the test if it hangs beyond 5s
    public async Task FetchAsync_CompletesWithinTimeout()
    {
        using var client = CreateMockClient(HttpStatusCode.OK, "fast");
        var fetcher = new DataFetcher(client);

        var result = await fetcher.FetchAsync("https://example.com");

        Assert.AreEqual("fast", result);
    }
}

// ── The mock handler ──

public class MockHttpMessageHandler : HttpMessageHandler
{
    private readonly Func<HttpRequestMessage, CancellationToken, Task<HttpResponseMessage>> _handler;

    public MockHttpMessageHandler(
        Func<HttpRequestMessage, CancellationToken, Task<HttpResponseMessage>> handler)
        => _handler = handler;

    protected override Task<HttpResponseMessage> SendAsync(
        HttpRequestMessage request, CancellationToken cancellationToken)
        => _handler(request, cancellationToken);
}
```

**Key takeaways:**

| Mechanism | Purpose |
|---|---|
| `CancellationTokenSource.Cancel()` | Simulates caller cancellation |
| `new CancellationTokenSource(timeout)` | Simulates a timeout at the application level |
| `[Timeout(ms)]` | Safety net — kills a hanging test so CI doesn't stall |
| `MockHttpMessageHandler` | Avoids real HTTP; respects `CancellationToken` via `Task.Delay` |

The `[Timeout]` attribute is a **test-level guardrail**, not a substitute for passing `CancellationToken` through your code. Always test cancellation explicitly by passing tokens to your method under test.
